#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e2+5;
int n,m,t;
PII mt[MAXN][MAXN];
int res,g[MAXN][MAXN];
bool st[MAXN][MAXN];
int dx[8]={1,-1,2,-2,1,-1,2,-2};
int dy[8]={2,2,1,1,-2,-2,-1,-1};
bool find(PII x)
{
    FOR(i,0,7)
    {
        int a=x.fst+dx[i];
        int b=x.snd+dy[i];
        if(a<1||a>n||b<1||b>m||g[a][b]||st[a][b]) continue;
        st[a][b]=true;
        if(mt[a][b].fst==0||find(mt[a][b]))
        {
            mt[a][b]=x;
            return true;
        }
    }
    return false;
}

signed main(void)
{
    n=read(),m=read(),t=read();
    FOR(i,1,t)
    {
        int x=read();
        int y=read();
        g[x][y]=1;
    }
    FOR(i,1,n)
    {
        FOR(j,1,m)
        {
            if(!g[i][j]&&(i+j)%2==0)
            {
                cl(st);
                if(find({i,j}))++res;
            }
        }
    }
    writeln(n*m-res-t);
    return false;
}
